/**
 * @ch 播放離場Spine動畫
 * @param index 索引 (0:橫 1:直 (0:只有一個方向時))
 * @param callback 動畫完成後的回調
 */
private async PlayOutSpineAnim(index: number,totalRoundNumber: number,totalWin: number, callback?: () => void) : Promise<void>
{
    if (index < 0 || index >= this.m_outSpines.length) {

        // 即使 index 無效，仍然呼叫 callback 以避免流程卡住
        callback?.();
        return;
    }

    const spine = this.m_outSpines[index];
    if (!spine) {

        // 即使 spine 不存在，仍然呼叫 callback 以避免流程卡住
        callback?.();
        return;
    }

    this.SetRoundNumber(totalRoundNumber);
    //this.SetTotalWin(totalWin);

    //AudioManager.Play(AudioManager.AudioClips.ChangeScene);

    spine.SetNodeActivity(true);
    spine.Stop();
    AudioManager.Play(AudioManager.AudioClips.FG_End);
    this.RunWin(totalWin);
    await spine.PlayInLoop(0, () => {
        spine.SetNodeActivity(false);
        callback?.();
    }, false);
    //await Define.Wait(this, this.m_outSpineAnimWaitTime);

}

private RunWin(totalWin: number)
{
    let duration = 4;
    let times = tools.divide( duration, 0.02 );
    let value = 0;
    let step = tools.divide( Number( totalWin ), times );
    tween( this.node )
        .repeat(
            times,
            tween()
                .call( () =>
                {
                    value = tools.plus( value, step );
                    if ( value >= totalWin )
                    {
                        value = totalWin;
                    }
                    for (let i = 0; i < this.m_totalWinLabels.length; i++) {
                        if (this.m_totalWinLabels[i]) {
                            this.m_totalWinLabels[i].string = tools.FormatNumberThousands( newBottombarManager.GetDisplayValue( value ), tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT );
                        }
                    }

                } )
                .delay( 0.02 )
        )
        .call( () =>
        {
            for (let i = 0; i < this.m_totalWinLabels.length; i++) {
                if (this.m_totalWinLabels[i]) {
                    this.m_totalWinLabels[i].string = tools.FormatNumberThousands( newBottombarManager.GetDisplayValue( totalWin ), tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT );
                }
            }

            let bet = newBottombarManager.GetNowBetValue();
            let odds = tools.divide( totalWin, bet );
            let audio = odds < 100 ? AudioManager.AudioClips.Pirate_FG_End1 : AudioManager.AudioClips.Pirate_FG_End2;
            AudioManager.Play( audio );
        } )
        .start();
}

