}

/**
 * @ch 播放免費遊戲背景音樂
 */
PlayFreeGameBgm()
{
    if (this.m_freeBgmId !== -1)
    {
        AudioManager.Stop(this.m_freeBgmId);
    }
    this.m_freeBgmId = AudioManager.PlayBackGround( AudioManager.AudioClips.FG_Bgm, true );
}

/**
 * @ch 停止免費遊戲背景音樂
 */
StopFreeGameBgm()
{
    if (this.m_freeBgmId !== -1)
    {
        AudioManager.Stop(this.m_freeBgmId);
        this.m_freeBgmId = -1;
    }
}

/**
 * @ch 暫停免費遊戲背景音樂
 */
PauseFreeGameBgm()
{
    if (this.m_freeBgmId !== -1)
    {
        AudioManager.Pause(this.m_freeBgmId);
    }
}

/**
 * @ch 恢復免費遊戲背景音樂
 */
ResumeFreeGameBgm()
{
    if (this.m_freeBgmId !== -1)
    {
        AudioManager.Resume(this.m_freeBgmId);
    }
}

/** @ch BGM 淡出（duration 秒） */
FadeBgmOut(duration: number = 0.5): void {
    if (this.m_bgmId !== -1) AudioManager.SetMusicFadeOut(this.m_bgmId, duration);
    if (this.m_freeBgmId !== -1) AudioManager.SetMusicFadeOut(this.m_freeBgmId, duration);
}

